/* AFFILIATE TRENDING SHOP - Complete Styles */

.shop-main {
    padding: 60px 0;
    background: var(--light);
}

/* Filters Bar */
.filters-bar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-wrap: wrap;
    gap: 20px;
    margin-bottom: 40px;
    padding: 20px;
    background: white;
    border-radius: 16px;
    border: 1px solid var(--border);
}

.category-filters {
    display: flex;
    gap: 12px;
    flex-wrap: wrap;
}

.filter-chip {
    padding: 8px 20px;
    background: #f3f4f6;
    border: none;
    border-radius: 40px;
    font-size: 0.85rem;
    font-weight: 500;
    cursor: pointer;
    transition: all 0.2s;
    color: var(--gray);
}

.filter-chip:hover {
    background: #e5e7eb;
    transform: translateY(-2px);
}

.filter-chip.active {
    background: linear-gradient(135deg, var(--primary), var(--secondary));
    color: white;
}

.sort-select {
    padding: 8px 20px;
    background: #f3f4f6;
    border: none;
    border-radius: 40px;
    font-size: 0.85rem;
    font-weight: 500;
    cursor: pointer;
    color: var(--gray);
}

.sort-select:focus {
    outline: none;
}

/* Products Grid */
.products-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
    gap: 30px;
    margin-bottom: 40px;
}

/* Product Card */
.product-card {
    background: white;
    border-radius: 20px;
    overflow: hidden;
    transition: all 0.3s ease;
    border: 1px solid var(--border);
    position: relative;
}

.product-card:hover {
    transform: translateY(-4px);
    box-shadow: 0 20px 30px -12px rgba(0, 0, 0, 0.1);
    border-color: var(--primary);
}

.product-badge {
    position: absolute;
    top: 12px;
    left: 12px;
    padding: 4px 12px;
    border-radius: 20px;
    font-size: 0.7rem;
    font-weight: 600;
    z-index: 2;
}

.product-badge.bestseller {
    background: linear-gradient(135deg, #f59e0b, #d97706);
    color: white;
}

.product-badge.trending {
    background: linear-gradient(135deg, #ff4757, #e11d48);
    color: white;
}

.product-badge.discount {
    background: linear-gradient(135deg, #10b981, #059669);
    color: white;
    right: 12px;
    left: auto;
}

.product-image {
    width: 100%;
    aspect-ratio: 4 / 3;
    overflow: hidden;
    background: #f9fafb;
}

.product-image img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: transform 0.5s ease;
}

.product-card:hover .product-image img {
    transform: scale(1.05);
}

.product-info {
    padding: 20px;
}

.product-category {
    font-size: 0.7rem;
    text-transform: uppercase;
    letter-spacing: 1px;
    color: var(--primary);
    font-weight: 600;
    margin-bottom: 8px;
}

.product-title {
    font-size: 1.1rem;
    font-weight: 600;
    line-height: 1.4;
    margin-bottom: 10px;
    color: var(--dark);
}

.product-description {
    font-size: 0.8rem;
    color: var(--gray);
    line-height: 1.5;
    margin-bottom: 15px;
}

.product-rating {
    display: flex;
    align-items: center;
    gap: 8px;
    margin-bottom: 12px;
}

.stars {
    color: #fbbf24;
    font-size: 0.85rem;
    letter-spacing: 2px;
}

.rating-count {
    font-size: 0.7rem;
    color: var(--gray-light);
}

.product-price {
    display: flex;
    align-items: baseline;
    gap: 10px;
    margin-bottom: 16px;
}

.current-price {
    font-size: 1.25rem;
    font-weight: 700;
    color: var(--dark);
}

.original-price {
    font-size: 0.85rem;
    color: var(--gray-light);
    text-decoration: line-through;
}

.view-product-btn {
    width: 100%;
    padding: 12px;
    background: linear-gradient(135deg, var(--primary), var(--secondary));
    color: white;
    border: none;
    border-radius: 40px;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.2s;
}

.view-product-btn:hover {
    transform: scale(1.02);
    box-shadow: 0 4px 12px rgba(102, 126, 234, 0.3);
}

/* Affiliate Disclosure */
.affiliate-disclosure {
    text-align: center;
    padding: 20px;
    background: #f8f9fa;
    border-radius: 12px;
    margin-top: 20px;
}

.affiliate-disclosure p {
    font-size: 0.75rem;
    color: var(--gray-light);
}

/* Responsive */
@media (max-width: 768px) {
    .filters-bar {
        flex-direction: column;
        align-items: stretch;
    }
    
    .category-filters {
        overflow-x: auto;
        flex-wrap: nowrap;
        padding-bottom: 8px;
    }
    
    .products-grid {
        grid-template-columns: 1fr;
        gap: 20px;
    }
    
    .product-title {
        font-size: 1rem;
    }
}

@media (max-width: 640px) {
    .shop-main {
        padding: 40px 0;
    }
}

