<body>
    <div class="sub-header">
        <div class="container">
            <a href="/categories/entertainment/" class="back-link">← Back to Entertainment</a>
            <h1>📚 Books</h1>
            <p>Book reviews, reading lists, and literary analysis. Discover your next great read.</p>
        </div>
    </div>

    <div class="container">
        <div class="posts-section">
            <h2>Latest in Books</h2>
            <div class="posts-grid" id="postsGrid">
                <div class="loading">Loading articles...</div>
            </div>
            <div class="pagination" id="pagination"></div>
        </div>
    </div>

    <script>
        const CATEGORY = 'entertainment';
        const SUBCATEGORY = 'books';
        let currentPage = 1;
        const POSTS_PER_PAGE = 9;
        let allPosts = [];

        async function loadContent() {
            try {
                console.log('1. Starting to load content...');

                // Direct fetch to JSON file
                const response = await fetch('/data/posts.json?t=' + Date.now());
                console.log('2. Fetch response status:', response.status);

                if (!response.ok) {
                    throw new Error(`HTTP error! status: ${response.status}`);
                }

                const data = await response.json();
                console.log('3. Data loaded, type:', Array.isArray(data) ? 'Array' : 'Object');
                console.log('4. Data structure:', Object.keys(data));

                // Extract posts array (handle both formats)
                let postsArray = [];
                if (Array.isArray(data)) {
                    postsArray = data;
                    console.log('5. Data is direct array, length:', postsArray.length);
                } else if (data.posts && Array.isArray(data.posts)) {
                    postsArray = data.posts;
                    console.log('5. Data has posts array, length:', postsArray.length);
                } else {
                    console.error('5. Unknown data format:', data);
                }

                // Filter by category and subcategory
                allPosts = postsArray.filter(post => {
                    return post.category === CATEGORY && post.subcategory === SUBCATEGORY;
                });

                console.log(`6. Filtered posts for ${CATEGORY}/${SUBCATEGORY}: ${allPosts.length}`);

                if (allPosts.length > 0) {
                    console.log('7. First post sample:', {
                        id: allPosts[0].id,
                        title: allPosts[0].title,
                        category: allPosts[0].category,
                        subcategory: allPosts[0].subcategory
                    });
                }

                if (allPosts.length === 0) {
                    document.getElementById('postsGrid').innerHTML = '<div class="loading">No book articles yet. Check back soon.</div>';
                    return;
                }

                renderPosts();

            } catch (error) {
                console.error('ERROR loading content:', error);
                document.getElementById('postsGrid').innerHTML = `<div class="error">Error: ${error.message}. Please check console for details.</div>`;
            }
        }

        function renderPosts() {
            const start = (currentPage - 1) * POSTS_PER_PAGE;
            const pagePosts = allPosts.slice(start, start + POSTS_PER_PAGE);

            const postsGrid = document.getElementById('postsGrid');
            if (!postsGrid) return;

            postsGrid.innerHTML = pagePosts.map(post => `
                <div class="post-card">
                    <div class="post-category">${(post.subcategory || 'BOOKS').toUpperCase()}</div>
                    <h3><a href="/posts/index.html?id=${post.id}">${escapeHtml(post.title)}</a></h3>
                    <p>${escapeHtml((post.excerpt || '').substring(0, 120))}...</p>
                    <div class="post-meta">
                        <span>📅 ${post.date || 'Recent'}</span>
                        <span>🕐 ${post.readTime || '5'} min read</span>
                        <span>👁️ ${(post.views || 0).toLocaleString()} views</span>
                    </div>
                </div>
            `).join('');

            renderPagination();
        }

        function renderPagination() {
            const totalPages = Math.ceil(allPosts.length / POSTS_PER_PAGE);
            if (totalPages <= 1) return;

            let html = '';
            if (currentPage > 1) html += `<a href="#" class="page-link" data-page="${currentPage-1}">← Prev</a>`;

            for (let i = 1; i <= totalPages; i++) {
                if (i === 1 || i === totalPages || (i >= currentPage-2 && i <= currentPage+2)) {
                    html += `<a href="#" class="page-link ${i === currentPage ? 'active' : ''}" data-page="${i}">${i}</a>`;
                } else if (i === currentPage-3 || i === currentPage+3) {
                    html += `<span class="page-link">...</span>`;
                }
            }

            if (currentPage < totalPages) html += `<a href="#" class="page-link" data-page="${currentPage+1}">Next →</a>`;
            document.getElementById('pagination').innerHTML = html;

            document.querySelectorAll('.page-link[data-page]').forEach(link => {
                link.addEventListener('click', (e) => {
                    e.preventDefault();
                    currentPage = parseInt(link.dataset.page);
                    renderPosts();
                    window.scrollTo({ top: 300, behavior: 'smooth' });
                });
            });
        }

        function escapeHtml(str) {
            if (!str) return '';
            return String(str)
                .replace(/&/g, '&amp;')
                .replace(/</g, '&lt;')
                .replace(/>/g, '&gt;')
                .replace(/"/g, '&quot;')
                .replace(/'/g, '&#39;');
        }

        // Load when DOM is ready
        document.addEventListener('DOMContentLoaded', loadContent);
    </script>
</body>
</html>

