            <h1>🎮 Gaming</h1>
            <p>Video game reviews, industry news, and gaming culture. Level up your entertainment.</p>
        </div>
    </div>

    <div class="container">
        <div class="posts-section">
            <h2>Latest in Gaming</h2>
            <div class="posts-grid" id="postsGrid">
                <div class="loading">Loading articles...</div>
            </div>
            <div class="pagination" id="pagination"></div>
        </div>
    </div>

    <script>
        const CATEGORY = 'entertainment';
        const SUBCATEGORY = 'gaming';
        let currentPage = 1;
        const POSTS_PER_PAGE = 9;
        let allPosts = [];

        async function loadContent() {
            try {
                const response = await fetch('/data/posts.json?t=' + Date.now());
                if (!response.ok) throw new Error(`HTTP ${response.status}`);
                const data = await response.json();
                let postsArray = Array.isArray(data) ? data : (data.posts || []);
                allPosts = postsArray.filter(post => 
                    post.category === CATEGORY && post.subcategory === SUBCATEGORY
                );
                if (allPosts.length === 0) {
                    document.getElementById('postsGrid').innerHTML = '<div class="loading">No articles yet. Check back soon.</div>';
                    return;
                }
                renderPosts();
            } catch (error) {
                console.error('Error:', error);
                document.getElementById('postsGrid').innerHTML = '<div class="loading">Failed to load posts. Please refresh.</div>';
            }
        }

        function renderPosts() {
            const start = (currentPage - 1) * POSTS_PER_PAGE;
            const pagePosts = allPosts.slice(start, start + POSTS_PER_PAGE);
            document.getElementById('postsGrid').innerHTML = pagePosts.map(post => `
                <div class="post-card">
                    <div class="post-category">${(post.subcategory || 'gaming').toUpperCase()}</div>
                    <h3><a href="/posts/index.html?id=${post.id}">${escapeHtml(post.title)}</a></h3>
                    <p>${escapeHtml((post.excerpt || '').substring(0, 120))}...</p>
                    <div class="post-meta">
                        <span>📅 ${post.date || 'Recent'}</span>
                        <span>🕐 ${post.readTime || '5'} min read</span>
                        <span>👁️ ${(post.views || 0).toLocaleString()} views</span>
                    </div>
                </div>
            `).join('');
            renderPagination();
        }

        function renderPagination() {
            const totalPages = Math.ceil(allPosts.length / POSTS_PER_PAGE);
            if (totalPages <= 1) return;
            let html = '';
            if (currentPage > 1) html += `<a href="#" class="page-link" data-page="${currentPage-1}">← Prev</a>`;
            for (let i = 1; i <= totalPages; i++) {
                if (i === 1 || i === totalPages || (i >= currentPage-2 && i <= currentPage+2)) {
                    html += `<a href="#" class="page-link ${i === currentPage ? 'active' : ''}" data-page="${i}">${i}</a>`;
                } else if (i === currentPage-3 || i === currentPage+3) {
                    html += `<span class="page-link">...</span>`;
                }
            }
            if (currentPage < totalPages) html += `<a href="#" class="page-link" data-page="${currentPage+1}">Next →</a>`;
            document.getElementById('pagination').innerHTML = html;
            document.querySelectorAll('.page-link[data-page]').forEach(link => {
                link.addEventListener('click', (e) => {
                    e.preventDefault();
                    currentPage = parseInt(link.dataset.page);
                    renderPosts();
                    window.scrollTo({ top: 300, behavior: 'smooth' });
                });
            });
        }

        function escapeHtml(str) {
            if (!str) return '';
            return String(str).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;');
        }

        document.addEventListener('DOMContentLoaded', loadContent);
    </script>
