                let postsArray = Array.isArray(data) ? data : (data.posts || []);
                const posts = postsArray.filter(post => post.category === CATEGORY);

                console.log(`Found ${posts.length} growth posts`);

                if (posts.length === 0) {
                    document.getElementById('articlesGrid').innerHTML = '<div class="loading">No growth articles yet. Check back soon.</div>';
                    document.getElementById('trendingList').innerHTML = '<div class="loading">No trending articles yet.</div>';
                    return;
                }

                // Featured Post
                const featuredPost = posts.find(post => post.featured === true);
                const featuredSection = document.getElementById('featuredSection');

                if (featuredPost && featuredSection) {
                    featuredSection.style.display = 'block';
                    featuredSection.innerHTML = `
                        <div class="container">
                            <div class="featured-grid">
                                <div>
                                    <div class="featured-label">COVER STORY</div>
                                    <h2>${escapeHtml(featuredPost.title)}</h2>
                                    <p>${escapeHtml((featuredPost.excerpt || '').substring(0, 150))}...</p>
                                    <a href="/posts/index.html?id=${featuredPost.id}" style="color:#10b981; text-decoration:none; font-weight:500;">Read full story →</a>
                                </div>
                                <div class="featured-image">
                                    <img src="${featuredPost.image || 'https://picsum.photos/600/400?random=' + featuredPost.id}" alt="${escapeHtml(featuredPost.title)}">
                                </div>
                            </div>
                        </div>
                    `;
                }

                // Regular Articles
                const articlesGrid = document.getElementById('articlesGrid');
                const nonFeaturedPosts = posts.filter(post => post.featured !== true);

                if (nonFeaturedPosts.length > 0) {
                    articlesGrid.innerHTML = nonFeaturedPosts.map(article => `
                        <div class="article-card" onclick="location.href='/posts/index.html?id=${article.id}'">
                            <div class="article-image"><img src="${article.image || 'https://picsum.photos/400/250?random=' + article.id}" alt="${escapeHtml(article.title)}"></div>
                            <div class="article-content">
                                <div class="article-category">${(article.subcategory || 'GROWTH').toUpperCase()}</div>
                                <h3><a href="/posts/index.html?id=${article.id}">${escapeHtml(article.title)}</a></h3>
                                <p>${escapeHtml((article.excerpt || '').substring(0, 100))}...</p>
                                <div class="article-meta">
                                    <span>📅 ${article.date || 'Recent'}</span>
                                    <span>⏱️ ${article.readTime || '5'} min</span>
                                    <span>👁️ ${(article.views || 0).toLocaleString()}</span>
                                </div>
                            </div>
                        </div>
                    `).join('');
                } else {
                    articlesGrid.innerHTML = '<div class="loading">No articles yet. Check back soon.</div>';
                }

                // Trending List
                const trendingList = document.getElementById('trendingList');
                const trending = posts.filter(p => p.trending === true).slice(0, 5);

                if (trending.length > 0) {
                    trendingList.innerHTML = trending.map((post, idx) => `
                        <div class="trending-item">
                            <div class="trending-rank">0${idx + 1}</div>
                            <div><a href="/posts/index.html?id=${post.id}" style="color:#111827; text-decoration:none; font-weight:500;">${escapeHtml(post.title)}</a><div style="font-size:0.65rem; color:#9ca3af;">${(post.views || 0).toLocaleString()} reads</div></div>
                        </div>
                    `).join('');
                } else {
                    trendingList.innerHTML = '<div class="trending-item">No trending articles yet.</div>';
                }

            } catch (error) {
                console.error('Error loading content:', error);
                document.getElementById('articlesGrid').innerHTML = '<div class="loading">Failed to load articles. Please refresh.</div>';
            }
        }

        function escapeHtml(str) {
            if (!str) return '';
            return String(str)
                .replace(/&/g, '&amp;')
                .replace(/</g, '&lt;')
                .replace(/>/g, '&gt;')
                .replace(/"/g, '&quot;')
                .replace(/'/g, '&#39;');
        }

        document.addEventListener('DOMContentLoaded', loadContent);
    </script>
</body>
