<body>
    <div class="sub-header">
        <div class="container">
            <a href="/categories/technology/" class="back-link">← Back to Technology</a>
            <h1>🤖 Artificial Intelligence</h1>
            <p>Exploring machine learning, neural networks, and the AI revolution shaping our future.</p>
        </div>
    </div>

    <div class="container">
        <div class="posts-section">
            <h2>Latest in AI</h2>
            <div class="posts-grid" id="postsGrid">
                <div class="loading">Loading articles...</div>
            </div>
            <div class="pagination" id="pagination"></div>
        </div>
    </div>

    <script>
        const CATEGORY = 'technology';
        const SUBCATEGORY = 'ai';
        let currentPage = 1;
        const POSTS_PER_PAGE = 9;
        let allPosts = [];

        async function loadContent() {
            try {
                const response = await fetch('/data/posts.json');
                if (!response.ok) throw new Error('Network response was not ok');
                const data = await response.json();
                allPosts = data.posts.filter(post => 
                    post.category === CATEGORY && 
                    post.subcategory?.toLowerCase() === SUBCATEGORY
                );
                renderPosts();
            } catch (error) {
                console.error('Error loading content:', error);
                document.getElementById('postsGrid').innerHTML = '<div class="error-message">Failed to load articles. Please refresh the page.</div>';
                document.getElementById('pagination').innerHTML = '';
            }
        }

        function renderPosts() {
            if (allPosts.length === 0) {
                document.getElementById('postsGrid').innerHTML = '<div class="loading">No articles found in this category.</div>';
                document.getElementById('pagination').innerHTML = '';
                return;
            }

            const start = (currentPage - 1) * POSTS_PER_PAGE;
            const pagePosts = allPosts.slice(start, start + POSTS_PER_PAGE);

            document.getElementById('postsGrid').innerHTML = pagePosts.map(post => `
                <div class="post-card">
                    <div class="post-category">AI</div>
                    <h3><a href="/posts/index.html?id=${post.id}">${escapeHtml(post.title)}</a></h3>
                    <p>${escapeHtml(post.excerpt)}</p>
                    <div class="post-meta">
                        <span>📅 ${post.date || 'Recent'}</span>
                        <span>🕐 ${post.readTime || '5'} min read</span>
                        ${post.views ? `<span>👁️ ${post.views.toLocaleString()}</span>` : ''}
                    </div>
                </div>
            `).join('');

            renderPagination();
        }

        function renderPagination() {
            const totalPages = Math.ceil(allPosts.length / POSTS_PER_PAGE);
            if (totalPages <= 1) {
                document.getElementById('pagination').innerHTML = '';
                return;
            }

            let html = '';
            if (currentPage > 1) {
                html += `<a class="page-link" data-page="${currentPage - 1}">← Prev</a>`;
            }

            let startPage = Math.max(1, currentPage - 2);
            let endPage = Math.min(totalPages, currentPage + 2);

            if (startPage > 1) {
                html += `<a class="page-link" data-page="1">1</a>`;
                if (startPage > 2) html += `<span class="page-link" style="background:transparent;">...</span>`;
            }

            for (let i = startPage; i <= endPage; i++) {
                html += `<a class="page-link ${i === currentPage ? 'active' : ''}" data-page="${i}">${i}</a>`;
            }

            if (endPage < totalPages) {
                if (endPage < totalPages - 1) html += `<span class="page-link" style="background:transparent;">...</span>`;
                html += `<a class="page-link" data-page="${totalPages}">${totalPages}</a>`;
            }

            if (currentPage < totalPages) {
                html += `<a class="page-link" data-page="${currentPage + 1}">Next →</a>`;
            }

            document.getElementById('pagination').innerHTML = html;

            document.querySelectorAll('.page-link[data-page]').forEach(link => {
                link.addEventListener('click', (e) => {
                    e.preventDefault();
                    const newPage = parseInt(link.dataset.page, 10);
                    if (!isNaN(newPage) && newPage !== currentPage) {
                        currentPage = newPage;
                        renderPosts();
                        window.scrollTo({ top: 300, behavior: 'smooth' });
                    }
                });
            });
        }

        function escapeHtml(str) {
            if (!str) return '';
            return String(str)
                .replace(/&/g, '&amp;')
                .replace(/</g, '&lt;')
                .replace(/>/g, '&gt;')
                .replace(/"/g, '&quot;')
                .replace(/'/g, '&#39;');
        }

        loadContent();
    </script>
</body>
</html>

