    <div class="sub-header">
        <div class="container">
            <a href="/categories/technology/" class="back-link">← Back to Technology</a>
            <h1>🔒 Cybersecurity</h1>
            <p>Privacy, online safety, threat protection, and security best practices for individuals and organizations.</p>
        </div>
    </div>

    <div class="container">
        <div class="posts-section">
            <h2>Latest in Security</h2>
            <div class="posts-grid" id="postsGrid">
                <div class="loading">Loading articles...</div>
            </div>
            <div class="pagination" id="pagination"></div>
        </div>
    </div>

    <script>
        const CATEGORY = 'technology';
        const SUBCATEGORY = 'cybersecurity';
        let currentPage = 1;
        const POSTS_PER_PAGE = 9;
        let allPosts = [];

        async function loadContent() {
            try {
                const response = await fetch('/data/posts.json');
                if (!response.ok) throw new Error(`HTTP ${response.status}: Failed to fetch posts`);
                const data = await response.json();

                // Filter posts by category and subcategory (case-insensitive match for flexibility)
                allPosts = data.posts.filter(post => 
                    post.category === CATEGORY && 
                    post.subcategory?.toLowerCase() === SUBCATEGORY.toLowerCase()
                );
                renderPosts();
            } catch (error) {
                console.error('Error loading cybersecurity content:', error);
                const postsGrid = document.getElementById('postsGrid');
                if (postsGrid) {
                    postsGrid.innerHTML = '<div class="error-message">⚠️ Unable to load articles. Please refresh the page.</div>';
                }
                const pagination = document.getElementById('pagination');
                if (pagination) pagination.innerHTML = '';
            }
        }

        function renderPosts() {
            const postsGrid = document.getElementById('postsGrid');

            if (!allPosts.length) {
                postsGrid.innerHTML = '<div class="empty-message">🔐 No cybersecurity articles found yet. Check back soon for security insights and best practices.</div>';
                document.getElementById('pagination').innerHTML = '';
                return;
            }

            const start = (currentPage - 1) * POSTS_PER_PAGE;
            const pagePosts = allPosts.slice(start, start + POSTS_PER_PAGE);

            postsGrid.innerHTML = pagePosts.map(post => `
                <div class="post-card">
                    <div class="post-category">SECURITY</div>
                    <h3><a href="/posts/index.html?id=${post.id}">${escapeHtml(post.title)}</a></h3>
                    <p>${escapeHtml(post.excerpt)}</p>
                    <div class="post-meta">
                        <span>📅 ${escapeHtml(post.date) || 'Recent'}</span>
                        <span>🕐 ${escapeHtml(post.readTime) || '5'} min read</span>
                        ${post.views ? `<span>👁️ ${post.views.toLocaleString()}</span>` : ''}
                    </div>
                </div>
            `).join('');

            renderPagination();
        }

        function renderPagination() {
            const totalPages = Math.ceil(allPosts.length / POSTS_PER_PAGE);
            const paginationContainer = document.getElementById('pagination');

            if (totalPages <= 1) {
                paginationContainer.innerHTML = '';
                return;
            }

            let html = '';

            // Previous button
            if (currentPage > 1) {
                html += `<a class="page-link" data-page="${currentPage - 1}">← Prev</a>`;
            }

            // Page numbers with ellipsis for large pagination
            let startPage = Math.max(1, currentPage - 2);
            let endPage = Math.min(totalPages, currentPage + 2);

            if (startPage > 1) {
                html += `<a class="page-link" data-page="1">1</a>`;
                if (startPage > 2) html += `<span class="page-link" style="background:transparent; cursor:default;">...</span>`;
            }

            for (let i = startPage; i <= endPage; i++) {
                html += `<a class="page-link ${i === currentPage ? 'active' : ''}" data-page="${i}">${i}</a>`;
            }

            if (endPage < totalPages) {
                if (endPage < totalPages - 1) html += `<span class="page-link" style="background:transparent; cursor:default;">...</span>`;
                html += `<a class="page-link" data-page="${totalPages}">${totalPages}</a>`;
            }

            // Next button
            if (currentPage < totalPages) {
                html += `<a class="page-link" data-page="${currentPage + 1}">Next →</a>`;
            }

            paginationContainer.innerHTML = html;

            // Attach click handlers to pagination links
            document.querySelectorAll('.page-link[data-page]').forEach(link => {
                link.addEventListener('click', (e) => {
                    e.preventDefault();
                    const newPage = parseInt(link.getAttribute('data-page'), 10);
                    if (!isNaN(newPage) && newPage !== currentPage) {
                        currentPage = newPage;
                        renderPosts();
                        window.scrollTo({ top: 300, behavior: 'smooth' });
                    }
                });
            });
        }

        function escapeHtml(str) {
            if (!str) return '';
            return String(str)
                .replace(/&/g, '&amp;')
                .replace(/</g, '&lt;')
                .replace(/>/g, '&gt;')
                .replace(/"/g, '&quot;')
                .replace(/'/g, '&#39;');
        }

        // Initialize on DOM ready
        if (document.readyState === 'loading') {
            document.addEventListener('DOMContentLoaded', loadContent);
        } else {
            loadContent();
        }
    </script>
</body>
