        async function loadContent() {
            try {
                console.log('Fetching wealth posts from /data/posts.json...');
                const response = await fetch(`/api/v1/posts/page/1.json`);

                let allPosts = [];
                let useFallback = false;

                if (!response.ok) {
                    console.warn('Posts.json not available, using fallback wealth data');
                    useFallback = true;
                } else {
                    const data = await response.json();
                const allPosts = data.posts;
                    allPosts = Array.isArray(data) ? data : (data.posts || []);
                    if (allPosts.length === 0) useFallback = true;
                }

                let posts;
                if (useFallback) {
                    posts = fallbackWealthPosts.filter(post => post.category === CATEGORY);
                    console.log(`Using fallback wealth data: ${posts.length} posts`);
                } else {
                    posts = allPosts.filter(post => post.category === CATEGORY);
                    console.log(`Wealth posts found from API: ${posts.length}`);
                }

                if (posts.length === 0) {
                    document.getElementById('articlesGrid').innerHTML = '<div class="loading">No wealth articles yet. Check back soon for financial insights.</div>';
                    document.getElementById('trendingList').innerHTML = '<div class="loading">No trending articles yet.</div>';
                    return;
                }

                // Featured Post
                const featuredPost = posts.find(post => post.featured === true);
                const featuredSection = document.getElementById('featuredSection');

                if (featuredPost && featuredSection) {
                    featuredSection.style.display = 'block';
