                console.error('Error loading wealth content:', error);
                // Final fallback: display fallback data inline if network fails completely
                const fallbackPosts = fallbackWealthPosts.filter(p => p.category === CATEGORY);
                if (fallbackPosts.length) {
                    const articlesGrid = document.getElementById('articlesGrid');
                    const nonFeatured = fallbackPosts.filter(p => p.featured !== true);
