// ============================================
// SERVICE WORKER FOR TRENDING WEALTH
// PWA - Offline Support & Advanced Caching
// Version: 3.0.0
// ============================================

const CACHE_VERSION = 'v3_0_0';
const CACHE_NAME = `trendingwealth-${CACHE_VERSION}`;
const CRITICAL_CACHE = `critical-${CACHE_VERSION}`;
const IMAGE_CACHE = `images-${CACHE_VERSION}`;
const API_CACHE = `api-${CACHE_VERSION}`;
const PAGE_CACHE = `pages-${CACHE_VERSION}`;

// ============================================
// STATIC ASSETS TO CACHE IMMEDIATELY
// ============================================
const CRITICAL_ASSETS = [
  '/',
  '/index.html',
  '/404.html',
  '/offline.html',
  '/manifest.json',
  '/assets/css/critical.css',
  '/assets/js/critical.js',
  '/assets/images/logo.png',
  '/assets/images/icon-192.png',
  '/assets/images/icon-512.png',
  '/api/v1/categories.json'
];

// ============================================
// CACHE STRATEGIES
// ============================================
const STRATEGIES = {
  STALE_WHILE_REVALIDATE: 'stale-while-revalidate',
  CACHE_FIRST: 'cache-first',
  NETWORK_FIRST: 'network-first',
  CACHE_ONLY: 'cache-only',
  NETWORK_ONLY: 'network-only'
};

// ============================================
// INSTALL EVENT - Cache critical assets
// ============================================
self.addEventListener('install', (event) => {
  console.log('[SW] Installing new version:', CACHE_VERSION);
  
  event.waitUntil(
    (async () => {
      // Open critical cache
      const criticalCache = await caches.open(CRITICAL_CACHE);
      await criticalCache.addAll(CRITICAL_ASSETS);
      
      // Open main cache
      const mainCache = await caches.open(CACHE_NAME);
      await mainCache.addAll(CRITICAL_ASSETS);
      
      // Skip waiting to activate immediately
      await self.skipWaiting();
    })()
  );
});

// ============================================
// ACTIVATE EVENT - Clean up old caches
// ============================================
self.addEventListener('activate', (event) => {
  console.log('[SW] Activating new version:', CACHE_VERSION);
  
  event.waitUntil(
    (async () => {
      // Get all cache keys
      const cacheKeys = await caches.keys();
      const oldCaches = cacheKeys.filter(key => 
        key.includes('trendingwealth') && 
        !key.includes(CACHE_VERSION) &&
        !key.includes(CRITICAL_CACHE) &&
        !key.includes(IMAGE_CACHE) &&
        !key.includes(API_CACHE) &&
        !key.includes(PAGE_CACHE)
      );
      
      // Delete old caches
      await Promise.all(oldCaches.map(key => caches.delete(key)));
      
      // Claim clients
      await self.clients.claim();
      
      // Send message to clients about update
      const clients = await self.clients.matchAll();
      clients.forEach(client => {
        client.postMessage({
          type: 'SW_UPDATED',
          version: CACHE_VERSION
        });
      });
    })()
  );
});

// ============================================
// FETCH EVENT - Handle all network requests
// ============================================
self.addEventListener('fetch', (event) => {
  const { request } = event;
  const url = new URL(request.url);
  
  // Skip non-GET requests
  if (request.method !== 'GET') {
    return;
  }
  
  // Skip Chrome extension requests
  if (url.protocol === 'chrome-extension:') {
    return;
  }
  
  // Skip analytics and tracking
  if (url.hostname.includes('google-analytics.com') ||
      url.hostname.includes('googletagmanager.com') ||
      url.hostname.includes('doubleclick.net')) {
    return;
  }
  
  // ============================================
  // STRATEGY 1: HTML Pages - Network First
  // ============================================
  if (request.destination === 'document') {
    event.respondWith(networkFirstStrategy(request));
    return;
  }
  
  // ============================================
  // STRATEGY 2: Images - Cache First
  // ============================================
  if (request.destination === 'image') {
    event.respondWith(cacheFirstStrategy(request, IMAGE_CACHE));
    return;
  }
  
  // ============================================
  // STRATEGY 3: CSS/JS - Stale While Revalidate
  // ============================================
  if (request.destination === 'style' || request.destination === 'script') {
    event.respondWith(staleWhileRevalidateStrategy(request, CACHE_NAME));
    return;
  }
  
  // ============================================
  // STRATEGY 4: API Calls - Network First with Cache Fallback
  // ============================================
  if (url.pathname.startsWith('/api/')) {
    event.respondWith(apiStrategy(request));
    return;
  }
  
  // ============================================
  // STRATEGY 5: Fonts - Cache Only
  // ============================================
  if (request.destination === 'font') {
    event.respondWith(cacheFirstStrategy(request, CACHE_NAME));
    return;
  }
  
  // ============================================
  // DEFAULT: Stale While Revalidate
  // ============================================
  event.respondWith(staleWhileRevalidateStrategy(request, CACHE_NAME));
});

// ============================================
// STRATEGY IMPLEMENTATIONS
// ============================================

/**
 * Network First - Try network, fallback to cache
 */
async function networkFirstStrategy(request, cacheName = PAGE_CACHE) {
  const cache = await caches.open(cacheName);
  
  try {
    // Try network
    const networkResponse = await fetch(request);
    
    // Cache successful response
    if (networkResponse && networkResponse.status === 200) {
      cache.put(request, networkResponse.clone());
    }
    
    return networkResponse;
  } catch (error) {
    // Network failed, try cache
    const cachedResponse = await cache.match(request);
    if (cachedResponse) {
      return cachedResponse;
    }
    
    // Return offline page for HTML requests
    if (request.destination === 'document') {
      const offlinePage = await cache.match('/offline.html');
      if (offlinePage) {
        return offlinePage;
      }
    }
    
    throw error;
  }
}

/**
 * Cache First - Try cache first, fallback to network
 */
async function cacheFirstStrategy(request, cacheName) {
  const cache = await caches.open(cacheName);
  const cachedResponse = await cache.match(request);
  
  if (cachedResponse) {
    // Update cache in background
    fetch(request).then(response => {
      if (response && response.status === 200) {
        cache.put(request, response);
      }
    }).catch(() => {});
    
    return cachedResponse;
  }
  
  // Not in cache, fetch from network
  const networkResponse = await fetch(request);
  if (networkResponse && networkResponse.status === 200) {
    cache.put(request, networkResponse.clone());
  }
  
  return networkResponse;
}

/**
 * Stale While Revalidate - Return cached, update in background
 */
async function staleWhileRevalidateStrategy(request, cacheName) {
  const cache = await caches.open(cacheName);
  const cachedResponse = await cache.match(request);
  
  // Update cache in background
  const fetchPromise = fetch(request).then(response => {
    if (response && response.status === 200) {
      cache.put(request, response.clone());
    }
    return response;
  }).catch(() => {});
  
  // Return cached response immediately if available
  if (cachedResponse) {
    event.waitUntil(fetchPromise);
    return cachedResponse;
  }
  
  // No cache, wait for network
  return await fetchPromise;
}

/**
 * API Strategy - Network with short cache
 */
async function apiStrategy(request) {
  const cache = await caches.open(API_CACHE);
  
  try {
    // Try network first
    const networkResponse = await fetch(request);
    
    if (networkResponse && networkResponse.status === 200) {
      // Clone response before caching
      const responseToCache = networkResponse.clone();
      
      // Cache with expiration headers
      const headers = new Headers(responseToCache.headers);
      headers.set('X-Cache-Date', new Date().toISOString());
      headers.set('X-Cache-TTL', '60');
      
      const cachedResponse = new Response(responseToCache.body, {
        status: responseToCache.status,
        statusText: responseToCache.statusText,
        headers: headers
      });
      
      cache.put(request, cachedResponse);
    }
    
    return networkResponse;
  } catch (error) {
    // Network failed, try cache
    const cachedResponse = await cache.match(request);
    if (cachedResponse) {
      // Check if cache is still valid (5 minutes)
      const cacheDate = cachedResponse.headers.get('X-Cache-Date');
      if (cacheDate) {
        const age = (new Date() - new Date(cacheDate)) / 1000;
        if (age < 300) { // 5 minutes
          return cachedResponse;
        }
      } else {
        return cachedResponse;
      }
    }
    
    // Return empty data
    return new Response(JSON.stringify({ error: 'Offline', data: [] }), {
      headers: { 'Content-Type': 'application/json' }
    });
  }
}

// ============================================
// BACKGROUND SYNC - Offline actions
// ============================================
self.addEventListener('sync', (event) => {
  if (event.tag === 'sync-newsletter') {
    event.waitUntil(syncNewsletterSubscriptions());
  }
  
  if (event.tag === 'sync-affiliate-clicks') {
    event.waitUntil(syncAffiliateClicks());
  }
});

async function syncNewsletterSubscriptions() {
  const cache = await caches.open('pending-subscriptions');
  const requests = await cache.keys();
  
  for (const request of requests) {
    try {
      const response = await fetch(request);
      if (response.ok) {
        await cache.delete(request);
      }
    } catch (error) {
      console.error('Failed to sync subscription:', error);
    }
  }
}

async function syncAffiliateClicks() {
  const cache = await caches.open('pending-clicks');
  const requests = await cache.keys();
  
  for (const request of requests) {
    try {
      const response = await fetch(request);
      if (response.ok) {
        await cache.delete(request);
      }
    } catch (error) {
      console.error('Failed to sync click:', error);
    }
  }
}

// ============================================
// PUSH NOTIFICATIONS
// ============================================
self.addEventListener('push', (event) => {
  if (!event.data) return;
  
  const data = event.data.json();
  
  const options = {
    body: data.body,
    icon: '/assets/images/icon-192.png',
    badge: '/assets/images/badge-72.png',
    vibrate: [200, 100, 200],
    data: {
      url: data.url || '/',
      dateOfArrival: Date.now()
    },
    actions: [
      {
        action: 'read',
        title: 'Read Now'
      },
      {
        action: 'dismiss',
        title: 'Dismiss'
      }
    ]
  };
  
  event.waitUntil(
    self.registration.showNotification(data.title, options)
  );
});

// ============================================
// NOTIFICATION CLICK HANDLER
// ============================================
self.addEventListener('notificationclick', (event) => {
  event.notification.close();
  
  const url = event.notification.data.url;
  
  event.waitUntil(
    clients.matchAll({ type: 'window', includeUncontrolled: true })
      .then(windowClients => {
        // Check if there's already a window/tab open with the target URL
        for (let client of windowClients) {
          if (client.url === url && 'focus' in client) {
            return client.focus();
          }
        }
        // If not, open a new window/tab
        if (clients.openWindow) {
          return clients.openWindow(url);
        }
      })
  );
});

// ============================================
// MESSAGE HANDLER
// ============================================
self.addEventListener('message', (event) => {
  const { type, data } = event.data;
  
  switch (type) {
    case 'PREFETCH':
      prefetchURL(data.url);
      break;
      
    case 'SKIP_WAITING':
      self.skipWaiting();
      break;
      
    case 'CLEAR_CACHE':
      clearCache(data.cacheName);
      break;
      
    case 'GET_CACHE_SIZE':
      getCacheSize().then(size => {
        event.source.postMessage({ type: 'CACHE_SIZE', size });
      });
      break;
      
    default:
      console.log('[SW] Unknown message type:', type);
  }
});

// ============================================
// UTILITY FUNCTIONS
// ============================================

async function prefetchURL(url) {
  const cache = await caches.open(CACHE_NAME);
  const response = await fetch(url);
  if (response && response.status === 200) {
    await cache.put(url, response);
  }
}

async function clearCache(cacheName) {
  if (cacheName) {
    await caches.delete(cacheName);
  } else {
    const keys = await caches.keys();
    await Promise.all(keys.map(key => caches.delete(key)));
  }
}

async function getCacheSize() {
  const keys = await caches.keys();
  let totalSize = 0;
  
  for (const key of keys) {
    const cache = await caches.open(key);
    const requests = await cache.keys();
    
    for (const request of requests) {
      const response = await cache.match(request);
      const blob = await response.blob();
      totalSize += blob.size;
    }
  }
  
  return totalSize;
}

// ============================================
// PERIODIC BACKGROUND SYNC (for updates)
// ============================================
self.addEventListener('periodicsync', (event) => {
  if (event.tag === 'update-content') {
    event.waitUntil(updateContent());
  }
});

async function updateContent() {
  const cache = await caches.open(PAGE_CACHE);
  
  // Update critical pages
  const pages = ['/', '/categories/technology/', '/categories/wealth/'];
  
  for (const page of pages) {
    try {
      const response = await fetch(page);
      if (response && response.status === 200) {
        await cache.put(page, response);
      }
    } catch (error) {
      console.error('Failed to update:', page, error);
    }
  }
}

// ============================================
// LOGGING (Development only)
// ============================================
if (self.location.hostname === 'localhost') {
  self.addEventListener('fetch', (event) => {
